byte :: alias u8;

bool :: i8;
true  : bool : 1;
false : bool : 0;

streq :: func(a: []char, b: []char) -> bool {
  if (a.length != b.length) {
    return false;
  }
  for (i := 0; i < a.length; i = i + 1) {
    if (i >= b.length) {
      return false;
    }
    if (a[i] != b[i]) {
      return false;
    }
  }
  return true;
}

LOG_ERR : int : 3;   // shared level contract (0 debug .. 3 error); the `log` device reuses it.

#foreign {
  _exit      :: proc(code: int);
  // The diagnostic seam: panics below and the pluggable `log` device (extras/log) both emit here. A weak
  // default lives in runtime/log.c (stderr); a selected log backend's strong symbol overrides it. `[]char`
  // lowers to a bare pointer across the FFI, so the length is passed explicitly (as `os.write` does) —
  // length-based, no strlen wart.
  log_be_emit :: proc(level: int, own msg: []char, n: int);
}

@policy(bounds)
abort :: policy(len: int, i: int) {
  if (i < 0 || i >= len) {
    m := "arche: index out of bounds\n";
    log_be_emit(LOG_ERR, m, m.length)(_:);
    _exit(134);
  }
}

@policy(bounds)
clamp :: policy(len: int, i: int) {
  if (i < 0) {
    i = 0;
  }
  if (i >= len) {
    i = len - 1;
  }
}

@policy(bounds)
wrap :: policy(len: int, i: int) {
  i = ((i % len) + len) % len;
}

@policy(bounds)
undefined :: policy(len: int, i: int) {
}

@policy(divide)
zero :: policy(a: int, b: int) {
  if (b == 0) {
    a = 0;
    b = 1;
  }
}
@policy(divide)
abort :: policy(a: int, b: int) {
  if (b == 0) {
    m := "arche: divide by zero\n";
    log_be_emit(LOG_ERR, m, m.length)(_:);
    _exit(134);
  }
}
@policy(divide)
undefined :: policy(a: int, b: int) {
}

@policy(pool)
reject :: policy(count: int, cap: int, ok: int) {
  if (count >= cap) {
    ok = 0;
  }
}

@policy(pool)
abort :: policy(count: int, cap: int) {
  if (count >= cap) {
    m := "arche: pool full\n";
    log_be_emit(LOG_ERR, m, m.length)(_:);
    _exit(134);
  }
}

