#import { net str fmt }

/// Parse each request row's "METHOD SP TARGET SP VERSION" line into SPANS over its own `raw` buffer (no
/// copies; `raw_len` is the received byte count, never a NUL-terminated length): method/target as
/// `start`+`len` with the target's `?query` trimmed, and `ok` = 0 on a malformed line. The app owns the
/// request pool and runs this `each` over it.
parse_request_line :: map (
  query { raw, raw_len, method_start, method_len, target_start, target_len, ok }
)(ok, method_start, method_len, target_start, target_len) eff {
  ok           = 0;
  method_start = 0;
  method_len   = 0;
  target_start = 0;
  target_len   = 0;
  n := raw_len;
  if (n >= 5) {
    sp1 := str.find_char(raw, 0, n, ' ');
    sp2 := str.find_char(raw, sp1 + 1, n, ' ');
    if (sp1 < n && sp2 < n) {
      method_len = sp1;
      tstart := sp1 + 1;
      tend   := sp2;
      q      := str.find_char(raw, tstart, tend, '?');
      if (q < tend) {
        tend = q;
      }
      target_start = tstart;
      target_len   = tend - tstart;
      ok           = 1;
    }
  }
}

/// Content-Type for a path, chosen by file extension. Returns a NUL-terminated string literal — safe
/// to hand to `%s`. Matched on the NUL-terminated content (a char buffer's `.length` is its capacity).
/// Unknown extensions fall back to `application/octet-stream`.
mime_by_ext :: func(path: []char) -> []char {
  p := path[0: str.strlen(path)];
  if (str.ends_with(p, ".html")) {
    return "text/html; charset=utf-8";
  }
  if (str.ends_with(p, ".htm")) {
    return "text/html; charset=utf-8";
  }
  if (str.ends_with(p, ".css")) {
    return "text/css; charset=utf-8";
  }
  if (str.ends_with(p, ".js")) {
    return "application/javascript";
  }
  if (str.ends_with(p, ".json")) {
    return "application/json";
  }
  if (str.ends_with(p, ".png")) {
    return "image/png";
  }
  if (str.ends_with(p, ".jpg")) {
    return "image/jpeg";
  }
  if (str.ends_with(p, ".svg")) {
    return "image/svg+xml";
  }
  if (str.ends_with(p, ".txt")) {
    return "text/plain; charset=utf-8";
  }
  return "application/octet-stream";
}

/// Reason phrase for a status code. Returns a NUL-terminated literal — safe for `%s`.
reason :: func(status: int) -> []char {
  if (status == 200) {
    return "OK";
  }
  if (status == 400) {
    return "Bad Request";
  }
  if (status == 403) {
    return "Forbidden";
  }
  if (status == 404) {
    return "Not Found";
  }
  if (status == 405) {
    return "Method Not Allowed";
  }
  return "OK";
}

/// Send each prepared response row: build the status line + headers into `hdr`, send them over `sock`,
/// then the body iff `send_body` (0 for HEAD). The socket is a create-once resource on a separate
/// connection pool, reached by NESTING a `sock` fan inside.
respond :: map (query { sock }) eff {
  map (query { status, ctype, body, body_len, send_body, hdr }) eff {
    rs := reason(status);
    fmt.sprintf(
      _,
      "HTTP/1.1 %d %s\r\nContent-Type: %s\r\nContent-Length: %d\r\nConnection: close\r\n\r\n",
      status,
      rs,
      ctype,
      body_len,
    )(hdr, n:);
    net.send_n(sock, hdr, n)(_:, _:);
    if (send_body == 1) {
      net.send_n(sock, body, body_len)(_:, _:);
    }
  };
}

