#import { os mem }

stdin :: func() -> fd {
  return fd.stdin;
}
stdout :: func() -> fd {
  return fd.stdout;
}
stderr :: func() -> fd {
  return fd.stderr;
}

/// `|> clamp_fd` folds the raw i64 open result into an `fd` (errno < 0 clamped to 0). Callers UNCHANGED.
clamp_fd :: func(r: i64) -> fd {
  if (r < 0) {
    return fd(0);
  }
  return fd(r);
}
fopen_read :: func(path: []char) -> Eff(fd) {
  return os.sys_open(path, 0, 0)
    |> clamp_fd;
}
fopen_write :: func(path: []char) -> Eff(fd) {
  return os.sys_open(path, 577, 420)
    |> clamp_fd;
}
fwrite :: func(f: fd, buf: []char, n: int) -> Eff(i64) {
  return os.sys_write(i64(f), buf, n);
}

/// Buffer-fill reads: the buffer is the caller-allocated OUT (the kernel fills it); `k` is the byte count
/// (negative errno on failure — the caller cooks it). The caller allocates at the out-binding (variable
/// size): `io.fread(f, n)(buf: [256]char, k:); buf[0:k]` — or `(cb, k:)` into an existing/queried buffer.
fread :: func(f: fd, n: int) -> Eff([]char, i64) {
  return os.sys_read(i64(f), _, n);
}

read :: func(f: fd, n: int) -> Eff([]char, i64) {
  return fread(f, n);
}

fclose :: func(f: fd) -> Eff(i64) {
  return os.syscall(3, f, 0, 0, 0, 0, 0);
}

@drop(fd)
fd_autoclose :: proc(own f: fd) {
  fclose(f)(_:);
}

stdout_write :: func(buf: []char, n: int) -> Eff(i64) {
  return os.write(1, buf, n);
}
stderr_write :: func(buf: []char, n: int) -> Eff(i64) {
  return os.write(2, buf, n);
}
stdin_read :: func(n: int) -> Eff([]char, i64) {
  return os.read(0, n);
}

open :: func(own path: []char) -> Eff(fd) {
  return fopen_read(move path);
}
close :: func(f: fd) -> Eff(i64) {
  return fclose(f);
}
read_chunk :: func(f: fd, size: int) -> Eff([]char, i64) {
  return fread(f, size);
